&#125;
binding.editor.setEditorLanguage(language);


Apply Themes (With DayNight theme detection)Use ThemeRegistry.getInstance().setTheme() to apply themes.
int nightModeFlags &#x3D; getResources().getConfiguration().uiMode &amp; Configuration.UI_MODE_NIGHT_MASK;
switch (nightModeFlags) &#123;
case Configuration.UI_MODE_NIGHT_YES:
    ThemeRegistry.getInstance().setTheme(&quot;darcula&quot;);
    break;

case Configuration.UI_MODE_NIGHT_NO:
    ThemeRegistry.getInstance().setTheme(&quot;quietlight&quot;);
    break;

case Configuration.UI_MODE_NIGHT_UNDEFINED:

    break;
&#125;


Full source codepublic class MainActivity extends AppCompatActivity &#123;
    ActivityTestBinding binding;
    @Override
    protected void onCreate(Bundle savedInstanceState) &#123;
        super.onCreate(savedInstanceState);
        binding &#x3D; ActivityTestBinding.inflate(getLayoutInflater());
        setContentView(binding.getRoot());

        loadDefaultThemes();
        loadDefaultLanguages();

        ensureTextmateTheme();

        applyThemes();
        applyLanguages();

    &#125;

    private void loadDefaultThemes() &#123;

        try &#123;
            FileProviderRegistry.getInstance().addFileProvider(new AssetsFileResolver(getAssets()));

            String[] themes &#x3D; &#123;
                &quot;quietlight&quot;,
                &quot;darcula&quot;
            &#125;;
            var themeRegistry &#x3D; ThemeRegistry.getInstance();

            int i &#x3D; themes.length;
            for (int j &#x3D; 0; j &lt; i;) &#123;
                String name &#x3D; themes[j];
                var path &#x3D; &quot;textmate&#x2F;&quot; + name + &quot;.json&quot;;
                themeRegistry.loadTheme(new ThemeModel(IThemeSource.fromInputStream(FileProviderRegistry.getInstance().tryGetInputStream(path), path, null), name));
                j++;

            &#125;
        &#125; catch (Exception e) &#123;
            e.printStackTrace();
        &#125;

    &#125;

    public void loadDefaultLanguages() &#123;
        GrammarRegistry.getInstance().loadGrammars(&quot;textmate&#x2F;languages.json&quot;);
    &#125;

    public void ensureTextmateTheme() &#123;
        try &#123;
            var editorColorScheme &#x3D; binding.editor.getColorScheme();
            if (!(editorColorScheme instanceof TextMateColorScheme)) &#123;
                editorColorScheme &#x3D; TextMateColorScheme.create(ThemeRegistry.getInstance());
                binding.editor.setColorScheme(editorColorScheme);
            &#125;
        &#125; catch (Exception e) &#123;
            e.printStackTrace();
        &#125;
    &#125;

    public void applyThemes() &#123;

        int nightModeFlags &#x3D; getResources().getConfiguration().uiMode &amp; Configuration.UI_MODE_NIGHT_MASK;
        switch (nightModeFlags) &#123;
        case Configuration.UI_MODE_NIGHT_YES:
            ThemeRegistry.getInstance().setTheme(&quot;darcula&quot;);
            break;

        case Configuration.UI_MODE_NIGHT_NO:
            ThemeRegistry.getInstance().setTheme(&quot;quietlight&quot;);
            break;
        &#125;

    &#125;

    public void applyLanguages() &#123;

        ensureTextmateTheme();

        TextMateLanguage language;
        var editorLanguage &#x3D; binding.editor.getEditorLanguage();
        if (editorLanguage instanceof TextMateLanguage) &#123;
            language &#x3D; (TextMateLanguage) editorLanguage;
            language.updateLanguage(&quot;source.java&quot;);
        &#125; else &#123;
            language &#x3D; TextMateLanguage.create(&quot;source.java&quot;, true);
        &#125;
        binding.editor.setEditorLanguage(language);

    &#125;
&#125;


That’s all. I hope this blog post would help you.

當我們要建立應用程式時，載入對話框總是對我們來說尤其重要。在這篇文章，你將會學會如何建立自訂載入對話框。

過時的實現方式在以前，我們可以透過使用 ProgressDialog 類別實現載入對話框，但是這方式已經不再建議使用了。
ProgressDialog dialog &#x3D; new ProgressDialog(this);
dialog.setMessage(&quot;Loading...&quot;);

dialog.show(); &#x2F;&#x2F; to show the progress dialog
dialog.dismiss(); &#x2F;&#x2F; to close the progress dialog


利用自訂佈局建立載入對話框雖然 ProgressDialog 類別已經被棄用，但是我們仍能透過使用其他方式把其實現，在編寫程式之前，我們需要為它編寫佈局。

編寫全新佈局在這佈局，我們會定義一個 ProgressBar 和一個 TextView。
&lt;?xml version&#x3D;&quot;1.0&quot; encoding&#x3D;&quot;utf-8&quot;?&gt;
&lt;LinearLayout xmlns:android&#x3D;&quot;http:&#x2F;&#x2F;schemas.android.com&#x2F;apk&#x2F;res&#x2F;android&quot;
    android:layout_width&#x3D;&quot;match_parent&quot;
    android:layout_height&#x3D;&quot;match_parent&quot;&gt;
    &lt;LinearLayout
        android:layout_width&#x3D;&quot;match_parent&quot;
        android:layout_height&#x3D;&quot;wrap_content&quot;
        android:orientation&#x3D;&quot;horizontal&quot;
        android:padding&#x3D;&quot;20dp&quot;&gt;
        &lt;ProgressBar
            android:id&#x3D;&quot;@+id&#x2F;pbLoading&quot;
            style&#x3D;&quot;?android:attr&#x2F;progressBarStyle&quot;
            android:layout_width&#x3D;&quot;wrap_content&quot;
            android:layout_height&#x3D;&quot;wrap_content&quot;
            android:layout_marginLeft&#x3D;&quot;10dp&quot;
            android:layout_marginRight&#x3D;&quot;20dp&quot; &#x2F;&gt;
        &lt;TextView
            android:id&#x3D;&quot;@+id&#x2F;tvText&quot;
            android:layout_width&#x3D;&quot;wrap_content&quot;
            android:layout_height&#x3D;&quot;wrap_content&quot;
            android:layout_gravity&#x3D;&quot;center&quot;
            android:text&#x3D;&quot;TextView&quot; &#x2F;&gt;
    &lt;&#x2F;LinearLayout&gt;
&lt;&#x2F;LinearLayout&gt;


實現載入對話框我們需要使用 LayoutInflater 類別從而動態載入 layout_loading_dialog.xml 佈局。
View view &#x3D; getLayoutInflater().inflate(R.layout.layout_loading_dialog, null);

接著，我們需要使用 setView() 方法把佈局設定至對話框顯示佈局。






TIP
我們目前在使用的資源庫取至 MaterialAlertDialog，它跟 Android 系統預設的 AlertDialog 的使用方式類近。

MaterialAlertDialogBuilder dialog &#x3D; new MaterialAlertDialogBuilder(this);
dialog.setView(view)
      .setCancelable(false)
      .create()
      .show();


自訂載入對話框文字內容有時我們使用載入對話框，裏面顯示的文字未必是經常顯示一樣的，因此，我們在佈局內定義的 TextView，現在大派用場了。
我們要用 findViewById() 方法獲取 TextView，但問題在於它現在位於 layout_loading_dialog.xml 佈局，我們不能直接呼喚這函數，而要利用 view 變量來執行。
TextView tv &#x3D; view.findViewById(R.id.tvText);

當 TextView 能被獲取，我們便可以用 setText() 方法來動態修改文字內容。

利用函數重複調用在進行動態修改文字內容前，我們需要把程式結構改成一個模組，這樣便可以重複使用。
因此，你的函數應編寫成：
public void showMLoadingDialog(Activity activity, String text) &#123;
    View view &#x3D; activity.getLayoutInflater().inflate(R.layout.layout_loading_dialog, null);
    TextView tv &#x3D; v.findViewById(R.id.tvText);
    tvText.setText(text);

    MaterialAlertDialogBuilder dialog &#x3D; new MaterialAlertDialogBuilder(activity);
    dialog.setView(view)
          .setCancelable(false)
          .create().show();
&#125;

現在，你便可以調用這個函數來呼喚一個載入對話框。
showMLoadingDialog(this, &quot;Loading, Hello World!&quot;);


